contracts/CheckIn.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

interface IPointsCheckIn {
    function addPoints(address user, uint256 amount, uint256 streak) external;
}

interface IReferral {
    function hasReferrer(address user) external view returns (bool);
    function distributeReferralFees(address user, uint256 totalFee) external payable;
}

interface IStaking {
    function getPointsBoost(address user) external view returns (uint256);
}

contract CheckIn is Ownable, ReentrancyGuard {
    enum Tier { BASIC, PRO, WHALE }

    struct CheckInRecord {
        uint256 lastCheckIn;
        uint256 streak;
        uint256 totalCheckIns;
        Tier lastTier;
    }

    IPointsCheckIn public pointsContract;
    IReferral public referralContract;
    IStaking public stakingContract;
    address public prizePool;
    address public treasury;
    address public burnReserve;
    address public stakingRewards;

    uint256 public constant BASIC_THRESHOLD = 0.0015 ether;
    uint256 public constant PRO_THRESHOLD = 0.01 ether;
    uint256 public constant WHALE_THRESHOLD = 0.05 ether;

    uint256 public constant BASE_POINTS = 100;
    uint256 public constant STREAK_CAP = 7;
    uint256 public constant DAY = 86400;

    // ─── Fee Distribution (BNB) ──────────────────────────────────────
    //  50% Prize Pool       — weekly prizes for dynamic top leaderboard (up to 1000)
    //  15% Treasury         — operations, development, marketing
    //  20% Referral Tree    — 6-level rewards for referrers
    //  10% Buyback & Burn   — buy OAI on DEX, then burn
    //   5% Staking Rewards  — BNB rewards for OAI stakers
    uint256 public constant PRIZE_SHARE = 5000;      // 50%
    uint256 public constant TREASURY_SHARE = 1500;   // 15%
    uint256 public constant REFERRAL_SHARE = 2000;   // 20%
    uint256 public constant BURN_SHARE = 1000;       // 10%
    uint256 public constant STAKING_SHARE = 500;     // 5%

    mapping(address => CheckInRecord) public records;
    uint256 public totalCheckIns;
    uint256 public totalFeesCollected;

    event CheckedIn(
        address indexed user,
        uint256 amount,
        Tier tier,
        uint256 points,
        uint256 streak
    );

    constructor(
        address _points,
        address _referral,
        address _prizePool,
        address _treasury,
        address _burnReserve,
        address _stakingRewards
    ) Ownable(msg.sender) {
        pointsContract = IPointsCheckIn(_points);
        referralContract = IReferral(_referral);
        prizePool = _prizePool;
        treasury = _treasury;
        burnReserve = _burnReserve;
        stakingRewards = _stakingRewards;
    }

    function setStakingContract(address _staking) external onlyOwner {
        stakingContract = IStaking(_staking);
    }

    function setPointsContract(address _points) external onlyOwner {
        require(_points != address(0), "Zero points");
        pointsContract = IPointsCheckIn(_points);
    }

    function setReferralContract(address _referral) external onlyOwner {
        require(_referral != address(0), "Zero referral");
        referralContract = IReferral(_referral);
    }

    function setFeeReceivers(
        address _prizePool,
        address _treasury,
        address _burnReserve,
        address _stakingRewards
    ) external onlyOwner {
        require(_prizePool != address(0), "Zero prize");
        require(_treasury != address(0), "Zero treasury");
        require(_burnReserve != address(0), "Zero burn");
        require(_stakingRewards != address(0), "Zero staking");
        prizePool = _prizePool;
        treasury = _treasury;
        burnReserve = _burnReserve;
        stakingRewards = _stakingRewards;
    }

    function checkIn() external payable nonReentrant {
        require(msg.value >= BASIC_THRESHOLD, "Below minimum");

        CheckInRecord storage record = records[msg.sender];

        uint256 today = block.timestamp / DAY;
        uint256 lastDay = record.lastCheckIn / DAY;
        require(today > lastDay, "Already checked in today");

        // Calculate streak
        uint256 streak = 1;
        if (lastDay > 0 && today - lastDay == 1) {
            streak = record.streak + 1;
        }

        // Determine tier
        Tier tier = _getTier(msg.value);
        uint256 multiplier = _getMultiplier(tier);

        // Streak bonus: +50% at 7 days, linear scale
        uint256 streakBonus = streak >= STREAK_CAP ? 50 : (streak * 50) / STREAK_CAP;

        // Calculate points
        uint256 points = (BASE_POINTS * multiplier * (100 + streakBonus)) / 100;

        // Staking boost
        if (address(stakingContract) != address(0)) {
            uint256 boost = stakingContract.getPointsBoost(msg.sender);
            if (boost > 0) {
                points = (points * (10000 + boost)) / 10000;
            }
        }

        // Update record
        record.lastCheckIn = block.timestamp;
        record.streak = streak;
        record.totalCheckIns++;
        record.lastTier = tier;
        totalCheckIns++;
        totalFeesCollected += msg.value;

        // Add points
        pointsContract.addPoints(msg.sender, points, streak);

        // Distribute fees
        _distributeFees(msg.sender, msg.value);

        emit CheckedIn(msg.sender, msg.value, tier, points, streak);
    }

    function _distributeFees(address user, uint256 amount) internal {
        uint256 prizeAmount = (amount * PRIZE_SHARE) / 10000;
        uint256 treasuryAmount = (amount * TREASURY_SHARE) / 10000;
        uint256 referralAmount = (amount * REFERRAL_SHARE) / 10000;
        uint256 burnAmount = (amount * BURN_SHARE) / 10000;
        uint256 stakingAmount = amount - prizeAmount - treasuryAmount - referralAmount - burnAmount;

        (bool ok1, ) = prizePool.call{value: prizeAmount}("");
        require(ok1, "Prize transfer failed");

        (bool ok2, ) = treasury.call{value: treasuryAmount}("");
        require(ok2, "Treasury transfer failed");

        bool referralHandled = false;
        if (address(referralContract) != address(0) && referralAmount > 0) {
            try referralContract.hasReferrer(user) returns (bool hasRef) {
                if (hasRef) {
                    try referralContract.distributeReferralFees{value: referralAmount}(user, referralAmount) {
                        referralHandled = true;
                    } catch {}
                }
            } catch {}
        }

        if (!referralHandled) {
            (bool ok3, ) = treasury.call{value: referralAmount}("");
            require(ok3, "Referral fallback failed");
        }

        (bool ok4, ) = burnReserve.call{value: burnAmount}("");
        require(ok4, "Burn transfer failed");

        (bool ok5, ) = stakingRewards.call{value: stakingAmount}("");
        require(ok5, "Staking rewards failed");
    }

    function _getTier(uint256 amount) internal pure returns (Tier) {
        if (amount >= WHALE_THRESHOLD) return Tier.WHALE;
        if (amount >= PRO_THRESHOLD) return Tier.PRO;
        return Tier.BASIC;
    }

    function _getMultiplier(Tier tier) internal pure returns (uint256) {
        if (tier == Tier.WHALE) return 10;
        if (tier == Tier.PRO) return 3;
        return 1;
    }

    function getRecord(address user) external view returns (CheckInRecord memory) {
        return records[user];
    }
}

contracts/Points.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/AccessControl.sol";

contract Points is AccessControl {
    bytes32 public constant OPERATOR_ROLE = keccak256("OPERATOR_ROLE");

    struct UserPoints {
        uint256 points;
        uint256 weeklyPoints;
        uint256 streak;
        uint256 lastCheckIn;
        uint256 totalCheckIns;
        uint256 correctPredictions;
        uint256 totalPredictions;
    }

    mapping(address => UserPoints) public users;
    address[] public allUsers;
    mapping(address => bool) private _isUser;

    uint256 public totalPointsIssued;

    event PointsAdded(address indexed user, uint256 amount, uint256 total);
    event StreakUpdated(address indexed user, uint256 streak);
    event PredictionBonusAdded(address indexed user, uint256 bonus);

    constructor() {
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
    }

    function addPoints(address user, uint256 amount, uint256 streak) external onlyRole(OPERATOR_ROLE) {
        if (!_isUser[user]) {
            allUsers.push(user);
            _isUser[user] = true;
        }

        users[user].points += amount;
        users[user].weeklyPoints += amount;
        users[user].streak = streak;
        users[user].lastCheckIn = block.timestamp;
        users[user].totalCheckIns++;
        totalPointsIssued += amount;

        emit PointsAdded(user, amount, users[user].points);
        emit StreakUpdated(user, streak);
    }

    function addPredictionBonus(address user, uint256 bonus, bool correct) external onlyRole(OPERATOR_ROLE) {
        if (!_isUser[user]) {
            allUsers.push(user);
            _isUser[user] = true;
        }

        users[user].points += bonus;
        users[user].weeklyPoints += bonus;
        users[user].totalPredictions++;
        if (correct) users[user].correctPredictions++;
        totalPointsIssued += bonus;

        emit PredictionBonusAdded(user, bonus);
    }

    function resetWeeklyPoints(address[] calldata addrs) external onlyRole(OPERATOR_ROLE) {
        for (uint i = 0; i < addrs.length; i++) {
            users[addrs[i]].weeklyPoints = 0;
        }
    }

    function resetAllWeeklyPoints() external onlyRole(OPERATOR_ROLE) {
        for (uint i = 0; i < allUsers.length; i++) {
            users[allUsers[i]].weeklyPoints = 0;
        }
    }

    function resetWeeklyPointsBatch(uint256 start, uint256 count) external onlyRole(OPERATOR_ROLE) returns (uint256 processed) {
        uint256 len = allUsers.length;
        if (start >= len) return 0;
        uint256 end = start + count;
        if (end > len) end = len;
        for (uint256 i = start; i < end; i++) {
            users[allUsers[i]].weeklyPoints = 0;
        }
        return end - start;
    }

    function getUserPoints(address user) external view returns (UserPoints memory) {
        return users[user];
    }

    function getUserCount() external view returns (uint256) {
        return allUsers.length;
    }

    function getTopUsers(uint256 count) external view returns (address[] memory, uint256[] memory) {
        uint256 len = allUsers.length < count ? allUsers.length : count;
        address[] memory topAddrs = new address[](len);
        uint256[] memory topPts = new uint256[](len);

        for (uint i = 0; i < allUsers.length; i++) {
            uint256 pts = users[allUsers[i]].weeklyPoints;
            for (uint j = 0; j < len; j++) {
                if (pts > topPts[j]) {
                    for (uint k = len - 1; k > j; k--) {
                        topAddrs[k] = topAddrs[k - 1];
                        topPts[k] = topPts[k - 1];
                    }
                    topAddrs[j] = allUsers[i];
                    topPts[j] = pts;
                    break;
                }
            }
        }
        return (topAddrs, topPts);
    }
}

contracts/Prediction.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/AccessControl.sol";

interface IPoints {
    function addPredictionBonus(address user, uint256 bonus, bool correct) external;
    function users(address user) external view returns (
        uint256 points,
        uint256 weeklyPoints,
        uint256 streak,
        uint256 lastCheckIn,
        uint256 totalCheckIns,
        uint256 correctPredictions,
        uint256 totalPredictions
    );
}

contract Prediction is AccessControl {
    bytes32 public constant OPERATOR_ROLE = keccak256("OPERATOR_ROLE");

    enum Category { SPORTS, POLITICS, ECONOMY, CRYPTO, CLIMATE }

    struct PredictionEvent {
        uint256 id;
        string title;
        Category category;
        uint256 aiProbability; // 0-100
        uint256 deadline;
        bool resolved;
        bool outcome;
        uint256 totalVotesYes;
        uint256 totalVotesNo;
        address creator;
        bool isUserEvent;
        uint256 listingFee;
        string sourcePolicy;
    }

    struct UserVote {
        bool voted;
        bool prediction;
    }

    IPoints public pointsContract;
    address public treasury;
    uint256 public eventCount;

    uint256 public constant CORRECT_BONUS = 50;
    uint256 public constant BEAT_AI_BONUS = 100;
    uint256 public constant DAY = 86400;
    uint256 public constant USER_EVENT_FEE = 0.0015 ether;
    uint256 public constant USER_EVENT_COOLDOWN = DAY;
    uint256 public constant VERIFIED_CREATOR_COOLDOWN = DAY / 3;
    uint256 public constant VERIFIED_MIN_POINTS = 5000;
    uint256 public constant MAX_TITLE_LENGTH = 180;
    uint256 public constant MAX_SOURCE_POLICY_LENGTH = 120;
    uint256 public constant MAX_RESOLVE_BATCH = 300;

    mapping(uint256 => PredictionEvent) public events;
    mapping(uint256 => mapping(address => UserVote)) public userVotes;
    mapping(uint256 => address[]) public eventVoters;
    mapping(address => uint256) public nextUserEventAt;
    mapping(uint256 => bool) public resolveInProgress;
    mapping(uint256 => uint256) public resolveCursor;
    mapping(uint256 => uint256) public resolvedWinners;
    mapping(uint256 => bool) private _pendingOutcome;
    mapping(uint256 => bool) private _pendingAiWasRight;

    event EventCreated(uint256 indexed id, string title, Category category, uint256 deadline);
    event UserEventCreated(uint256 indexed id, address indexed creator, uint256 feePaid, uint256 nextAllowedAt);
    event VoteSubmitted(uint256 indexed eventId, address indexed user, bool prediction);
    event EventResolutionStarted(uint256 indexed id, bool outcome, uint256 voters);
    event EventResolutionProgress(uint256 indexed id, uint256 from, uint256 to, uint256 total);
    event EventResolved(uint256 indexed id, bool outcome, uint256 winnersCount);

    constructor(address _points, address _treasury) {
        require(_treasury != address(0), "Zero treasury");
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(OPERATOR_ROLE, msg.sender);
        pointsContract = IPoints(_points);
        treasury = _treasury;
    }

    function createEvent(
        string calldata title,
        Category category,
        uint256 deadline,
        uint256 aiProbability
    ) external onlyRole(OPERATOR_ROLE) returns (uint256) {
        require(deadline > block.timestamp, "Past deadline");
        require(aiProbability <= 100, "Invalid probability");

        eventCount++;
        events[eventCount] = PredictionEvent({
            id: eventCount,
            title: title,
            category: category,
            aiProbability: aiProbability,
            deadline: deadline,
            resolved: false,
            outcome: false,
            totalVotesYes: 0,
            totalVotesNo: 0,
            creator: address(0),
            isUserEvent: false,
            listingFee: 0,
            sourcePolicy: ""
        });

        emit EventCreated(eventCount, title, category, deadline);
        return eventCount;
    }

    function createUserEvent(
        string calldata title,
        Category category,
        uint256 deadline,
        string calldata sourcePolicy
    ) external payable returns (uint256) {
        require(bytes(title).length > 10 && bytes(title).length <= MAX_TITLE_LENGTH, "Invalid title length");
        require(bytes(sourcePolicy).length > 0 && bytes(sourcePolicy).length <= MAX_SOURCE_POLICY_LENGTH, "Invalid source");
        require(msg.value == USER_EVENT_FEE, "Invalid fee");
        require(deadline > block.timestamp + 10 minutes, "Deadline too soon");
        require(deadline < block.timestamp + 14 days, "Deadline too far");
        uint256 cooldown = getCreatorCooldown(msg.sender);
        require(block.timestamp >= nextUserEventAt[msg.sender], "Cooldown active");

        eventCount++;
        events[eventCount] = PredictionEvent({
            id: eventCount,
            title: title,
            category: category,
            aiProbability: 50,
            deadline: deadline,
            resolved: false,
            outcome: false,
            totalVotesYes: 0,
            totalVotesNo: 0,
            creator: msg.sender,
            isUserEvent: true,
            listingFee: msg.value,
            sourcePolicy: sourcePolicy
        });

        nextUserEventAt[msg.sender] = block.timestamp + cooldown;

        (bool sent, ) = payable(treasury).call{value: msg.value}("");
        require(sent, "Treasury transfer failed");

        emit EventCreated(eventCount, title, category, deadline);
        emit UserEventCreated(eventCount, msg.sender, msg.value, nextUserEventAt[msg.sender]);
        return eventCount;
    }

    function isVerifiedCreator(address user) public view returns (bool) {
        (uint256 points, , , , , , ) = pointsContract.users(user);
        return points >= VERIFIED_MIN_POINTS;
    }

    function getCreatorCooldown(address user) public view returns (uint256) {
        if (isVerifiedCreator(user)) return VERIFIED_CREATOR_COOLDOWN;
        return USER_EVENT_COOLDOWN;
    }

    function submitPrediction(uint256 eventId, bool _prediction) external {
        PredictionEvent storage evt = events[eventId];
        require(evt.id != 0, "Event not found");
        require(!evt.resolved, "Already resolved");
        require(!resolveInProgress[eventId], "Resolving in progress");
        require(block.timestamp < evt.deadline, "Past deadline");
        require(!userVotes[eventId][msg.sender].voted, "Already voted");
        (, , , uint256 lastCheckIn, , , ) = pointsContract.users(msg.sender);
        require(lastCheckIn / DAY == block.timestamp / DAY, "Check-in required today");

        userVotes[eventId][msg.sender] = UserVote(true, _prediction);
        eventVoters[eventId].push(msg.sender);

        if (_prediction) evt.totalVotesYes++;
        else evt.totalVotesNo++;

        emit VoteSubmitted(eventId, msg.sender, _prediction);
    }

    function resolveEvent(uint256 eventId, bool actualOutcome) external onlyRole(OPERATOR_ROLE) {
        _resolveEventBatch(eventId, actualOutcome, MAX_RESOLVE_BATCH);
    }

    function resolveEventBatch(uint256 eventId, bool actualOutcome, uint256 maxBatch)
        external
        onlyRole(OPERATOR_ROLE)
    {
        require(maxBatch > 0 && maxBatch <= 1000, "Bad batch");
        _resolveEventBatch(eventId, actualOutcome, maxBatch);
    }

    function _resolveEventBatch(uint256 eventId, bool actualOutcome, uint256 maxBatch) internal {
        PredictionEvent storage evt = events[eventId];
        require(evt.id != 0, "Event not found");
        require(!evt.resolved, "Already resolved");
        require(block.timestamp >= evt.deadline, "Before deadline");

        address[] storage voters = eventVoters[eventId];
        if (!resolveInProgress[eventId]) {
            resolveInProgress[eventId] = true;
            _pendingOutcome[eventId] = actualOutcome;
            _pendingAiWasRight[eventId] = (evt.aiProbability >= 50) == actualOutcome;
            emit EventResolutionStarted(eventId, actualOutcome, voters.length);
        }

        uint256 from = resolveCursor[eventId];
        uint256 to = from + maxBatch;
        if (to > voters.length) to = voters.length;

        for (uint256 i = from; i < to; i++) {
            UserVote memory vote = userVotes[eventId][voters[i]];
            bool userCorrect = vote.prediction == _pendingOutcome[eventId];
            if (userCorrect) {
                resolvedWinners[eventId]++;
                uint256 bonus = CORRECT_BONUS;
                if (!_pendingAiWasRight[eventId]) bonus += BEAT_AI_BONUS;
                pointsContract.addPredictionBonus(voters[i], bonus, true);
            } else {
                pointsContract.addPredictionBonus(voters[i], 0, false);
            }
        }

        resolveCursor[eventId] = to;
        emit EventResolutionProgress(eventId, from, to, voters.length);

        if (to == voters.length) {
            evt.resolved = true;
            evt.outcome = _pendingOutcome[eventId];
            resolveInProgress[eventId] = false;
            delete _pendingOutcome[eventId];
            delete _pendingAiWasRight[eventId];
            emit EventResolved(eventId, evt.outcome, resolvedWinners[eventId]);
        }
    }

    function getEvent(uint256 eventId) external view returns (PredictionEvent memory) {
        return events[eventId];
    }

    function getUserVote(uint256 eventId, address user) external view returns (UserVote memory) {
        return userVotes[eventId][user];
    }

    function getActiveEvents(uint256 limit) external view returns (PredictionEvent[] memory) {
        uint256 count = 0;
        for (uint i = eventCount; i > 0 && count < limit; i--) {
            if (!events[i].resolved && block.timestamp < events[i].deadline) count++;
        }

        PredictionEvent[] memory result = new PredictionEvent[](count);
        uint256 idx = 0;
        for (uint i = eventCount; i > 0 && idx < count; i--) {
            if (!events[i].resolved && block.timestamp < events[i].deadline) {
                result[idx++] = events[i];
            }
        }
        return result;
    }
}

